// Standard resilience handler (retry + circuit breaker + timeout)
builder.Services.AddHttpClient<ProductClient>()
    .AddStandardResilienceHandler(opt =>
    {
        opt.Retry.MaxRetryAttempts = 3;
        opt.Retry.Delay = TimeSpan.FromMilliseconds(200);
        opt.Retry.UseJitter = true;
        opt.CircuitBreaker.SamplingDuration = TimeSpan.FromSeconds(30);
        opt.CircuitBreaker.FailureRatio = 0.5;
        opt.TotalRequestTimeout.Timeout = TimeSpan.FromSeconds(10);
    });

// Custom pipeline với Hedging (critical path)
builder.Services.AddResiliencePipeline("payment", b => b
    .AddHedging(new HedgingStrategyOptions<HttpResponseMessage>
    {
        MaxHedgedAttempts = 2,
        Delay = TimeSpan.FromMilliseconds(200),
        ShouldHandle = args => args.Outcome.Result?.IsSuccessStatusCode == false
            ? PredicateResult.True() : PredicateResult.False()
    })
    .AddTimeout(TimeSpan.FromSeconds(5))
    .AddRetry(new RetryStrategyOptions
    {
        MaxRetryAttempts = 2,
        BackoffType = DelayBackoffType.Exponential,
        UseJitter = true
    }));
